'use strict';
// Ninja Adventure sprites (CC0, pixel-boy) — 16x16 grids.
// Characters: 4 cols (front, back, left, right) x 7 rows (rows 0-3 = walk frames).
// Monsters: 4 cols x 4 rows, same column order.
const SPRITE_DATA = {
  skins: {
    ninja: 'data:image/png;base64,',
    rookie: 'data:image/png;base64,',
    scout: 'data:image/png;base64,',
    monk: 'data:image/png;base64,',
    brawler: 'data:image/png;base64,',
    elder: 'data:image/png;base64,',
    shade: 'data:image/png;base64,',
    ranger: 'data:image/png;base64,',
  },
  foes: {
    f1: 'data:image/png;base64,',
    f2: 'data:image/png;base64,',
    f3: 'data:image/png;base64,',
    f4: 'data:image/png;base64,',
    f5: 'data:image/png;base64,',
    f6: 'data:image/png;base64,',
    f7: 'data:image/png;base64,',
    f8: 'data:image/png;base64,',
  },
  bosses: {
    crab: 'data:image/png;base64,',
    flame: 'data:image/png;base64,',
    beast: 'data:image/png;base64,',
    phoenix: 'data:image/png;base64,',
    fiend: 'data:image/png;base64,',
  },
};

// Loader: create Image objects for all sprites
const SPRITES = {};
for (const group of ['skins', 'foes', 'bosses']) {
  for (const key in SPRITE_DATA[group]) {
    const img = new Image();
    img.src = SPRITE_DATA[group][key];
    SPRITES[group + '.' + key] = img;
  }
}

function spriteReady(img) {
  return img && img.complete && img.naturalWidth > 0;
}
